                                                                        <label htmlFor={`event-${event.id}`} className="ml-3 flex-grow cursor-pointer"><span className="font-semibold text-text-primary">{formatEventName(event)}</span></label>
                                                                    </div>
                                                                    {(selectedEvents[event.id] as any)?.selected && (
