                        {/* SECTION INFORMASI BIAYA & INSTRUKSI PEMBAYARAN - DITAMPILKAN LEBIH AWAL */}
                        {!(competitionInfo?.isFree) && (
                            <Card className="border-2 border-primary/20 bg-primary/5">
