                                <div className="space-y-4">
                                    <div className="bg-surface p-4 rounded-lg border border-primary/20 shadow-sm">
                                        <div className="flex justify-between items-center mb-4 pb-4 border-b border-border">
                                            <div>
                                                <p className="text-xs text-text-secondary uppercase font-bold tracking-wider">Biaya Per Nomor</p>
                                                <p className="text-2xl font-black text-primary">Rp {(competitionInfo?.feePerEvent || 0).toLocaleString('id-ID')}</p>
                                            </div>
                                            <div className="text-right">
                                                <p className="text-xs text-text-secondary uppercase font-bold tracking-wider">Nomor Dipilih</p>
                                                <p className="text-2xl font-black text-primary">{selectedEventCount}</p>
                                            </div>
                                        </div>

                                        <div className="grid grid-cols-1 md:grid-cols-2 gap-4 items-start">
                                            <div>
                                                <p className="text-sm text-text-secondary font-medium">Tujuan Transfer:</p>
