                            {!formData.ageGroup && <p className="text-yellow-600 bg-yellow-50 p-3 rounded-md text-sm border border-yellow-200 font-medium">Silakan pilih Kelompok Umur (KU) terlebih dahulu di Langkah 1 untuk melihat daftar lomba.</p>}
                            <div className="space-y-2">
