                {regType === 'INDIVIDUAL' && !successMessage && (
                    <form onSubmit={handleSubmit} className="space-y-6 pb-20">
                        <div className="flex justify-start">
                            <Button variant="secondary" onClick={() => setRegType('CHOICE')}>&larr; Kembali ke Pilihan</Button>
