export const clearAllData = async () => {
    await Promise.all([
        supabase.from('event_results').delete().neq('event_id', '0'),
        supabase.from('event_entries').delete().neq('event_id', '0'),
        supabase.from('swimmers').delete().neq('id', '0'),
