                                        <h2 className="text-xl font-black flex items-center gap-2">
                                            <span className="bg-primary text-white w-8 h-8 rounded-full flex items-center justify-center text-sm">{isFree ? '2' : '3'}</span>
                                            Pilih Nomor Lomba
