// --- TYPES ---
type ReportType = 'schedule' | 'program' | 'results' | 'clubMedals' | 'clubSwimmerMedals' | 'swimmerTotal' | 'swimmerCategory' | 'brokenRecords';

interface ScheduledEvent extends SwimEvent {
    globalEventNumber: number;
