                    </div>
                )}

                <footer className="pt-8 mt-12 border-t-2 border-black text-center opacity-70 text-[9px] font-bold uppercase tracking-widest">
                     DICETAK PADA: {new Date().toLocaleString('id-ID')} | SYSTEM BY R.E.A.C.T | HALAMAN 1
                </footer>
            </div>
        </div>
    );
};

