const App: React.FC = () => {
  const [appStatus, setAppStatus] = useState<'loading' | 'ready'>('loading');
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [currentView, setCurrentView] = useState<View>(View.LOGIN);
  const [selectedEventId, setSelectedEventId] = useState<string | null>(null);
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const [navigationState, setNavigationState] = useState<any>(null);

  // Centralized state
  const [swimmers, setSwimmers] = useState<Swimmer[]>([]);
  const [events, setEvents] = useState<SwimEvent[]>([]);
  const [competitionInfo, setCompetitionInfo] = useState<CompetitionInfo | null>(null);
  const [isDataLoading, setIsDataLoading] = useState(true);

  // State for connection status
  const [internetStatus, setInternetStatus] = useState<'online' | 'offline'>('online');
  const [dbStatus, setDbStatus] = useState<'checking' | 'connected' | 'error' | 'offline' | 'reconnecting'>('checking');
  const [arduinoStatus, setArduinoStatus] = useState<ArduinoStatus>('unavailable');

  // Centralized data fetching function
  const refreshData = useCallback(async () => {
    setIsDataLoading(true);
    try {
      // Use the new serverless function to fetch all public data securely
      const { competitionInfo: infoData, swimmers: swimmersData, events: eventsData } = await getPublicData();
      setSwimmers(swimmersData);
      setEvents(eventsData);
      setCompetitionInfo(infoData);
    } catch (error: any) {
      console.error("Failed to refresh data from server:", error.message || JSON.stringify(error));
    } finally {
      setIsDataLoading(false);
    }
  }, []);

  // Initial data load and user check
  useEffect(() => {
    const checkUserAndLoadData = async () => {
        const user = getCurrentUser();
        setCurrentUser(user);

        const urlParams = new URLSearchParams(window.location.search);
        const publicView = urlParams.get('view');
        const entityId = urlParams.get('id');

        if (publicView === 'results') {
            setCurrentView(View.PUBLIC_RESULTS);
        } else if(publicView === 'registration') {
            setCurrentView(View.ONLINE_REGISTRATION);
        } else if(publicView === 'checkin' && entityId) {
            setSelectedEventId(entityId); // Reuse this state to store swimmerId
            setCurrentView(View.CHECKIN);
        } else if (user) {
            setCurrentView(View.ADMIN_DASHBOARD);
        } else {
            setCurrentView(View.LOGIN);
        }

        setAppStatus('ready');
    };

    checkUserAndLoadData();
  }, []);

  // Real-time data subscription and connection management
  useEffect(() => {
      const channel = supabase.channel('schema-db-changes');

      channel.on('postgres_changes', { event: '*', schema: 'public' }, (payload) => {
          console.log('Realtime change received! Refreshing data.', payload);
          refreshData();
      });

      channel.subscribe((status, err) => {
          if (status === 'SUBSCRIBED') {
              console.log('Realtime channel connected.');
              setDbStatus('connected');
              refreshData();
          }
          if (status === 'CHANNEL_ERROR') {
              console.error('Realtime channel error:', err);
              setDbStatus('error');
          }
          if (status === 'TIMED_OUT') {
              console.warn('Realtime channel timed out. Attempting to reconnect.');
              setDbStatus('reconnecting');
          }
      });

      return () => {
          supabase.removeChannel(channel);
      };
  }, [refreshData]);

  // Manages browser online/offline status
  useEffect(() => {
      const handleOnline = () => {
          setInternetStatus('online');
          setDbStatus('reconnecting'); 
      };

      const handleOffline = () => {
          setInternetStatus('offline');
          setDbStatus('offline');
      };

      if (navigator.onLine) {
          setInternetStatus('online');
      } else {
          setInternetStatus('offline');
          setDbStatus('offline');
      }

      window.addEventListener('online', handleOnline);
      window.addEventListener('offline', handleOffline);

      return () => {
          window.removeEventListener('online', handleOnline);
          window.removeEventListener('offline', handleOffline);
      };
  }, []);

  const handleArduinoStatusChange = useCallback((status: ArduinoStatus) => {
    setArduinoStatus(status);
  }, []);

  const handleLogin = () => {
    const user = getCurrentUser();
    setCurrentUser(user);
    if(user){
      setCurrentView(View.ADMIN_DASHBOARD);
      refreshData();
    }
  };

  const handleLogout = async () => {
    await logout();
    setCurrentUser(null);
    setCurrentView(View.LOGIN);
  };

  const navigateTo = (view: View, state: any = null) => {
    setCurrentView(view);
    setSelectedEventId(null);
    setNavigationState(state);
    setIsMenuOpen(false);
  }

  const handleSelectEvent = (id: string) => {
    setSelectedEventId(id);
    setCurrentView(View.RACES); 
  };

  const handleStartTiming = (id: string) => {
    setSelectedEventId(id);
    setCurrentView(View.LIVE_TIMING);
  };

  const handleBackToEvents = () => {
      setSelectedEventId(null);
      setCurrentView(View.RACES);
  }

  const handleShowPublicResults = () => {
      setCurrentView(View.PUBLIC_RESULTS);
  }

  const handleBackToLogin = () => {
      setCurrentView(View.LOGIN);
  }

  const handleShowRegistration = () => {
    setCurrentView(View.ONLINE_REGISTRATION);
  };

  if (appStatus === 'loading') {
    return (
      <div className="flex justify-center items-center h-screen bg-background">
        <Spinner />
        <p className="ml-4 text-text-secondary">Initializing Application...</p>
      </div>
    );
  }


  const renderContent = () => {
    const isLoading = isDataLoading;

    if (currentView === View.PUBLIC_RESULTS) {
        return <PublicResultsView 
            onAdminLogin={handleBackToLogin}
        />;
    }

    if (currentView === View.ONLINE_REGISTRATION) {
        return <OnlineRegistrationView
            competitionInfo={competitionInfo}
            onBackToLogin={handleBackToLogin}
            onRegistrationSuccess={refreshData}
        />;
    }

    if (currentView === View.CHECKIN && selectedEventId) {
        return <CheckinView
            swimmerId={selectedEventId}
            onBackToLogin={handleBackToLogin}
        />;
    }

    if (!currentUser) {
        return <LoginView 
            onLoginSuccess={handleLogin} 
            onShowPublicResults={handleShowPublicResults} 
            onShowRegistration={handleShowRegistration}
            competitionInfo={competitionInfo}
        />;
    }

    // Logged-in admin views
    if (currentView === View.LIVE_TIMING && selectedEventId) {
       return <LiveTimingView eventId={selectedEventId} onBack={handleBackToEvents} onDataUpdate={refreshData} swimmers={swimmers} competitionInfo={competitionInfo} onStatusChange={handleArduinoStatusChange} />;
    }
    if (currentView === View.RACES && selectedEventId) {
      return <EventDetailView eventId={selectedEventId} onBack={handleBackToEvents} onDataUpdate={refreshData} />;
    }

    switch (currentView) {
      case View.ADMIN_DASHBOARD:
        return <AdminDashboard swimmers={swimmers} events={events} competitionInfo={competitionInfo} isLoading={isLoading} navigateTo={navigateTo} />;
      case View.EVENT_SETTINGS:
        return <EventSettingsView 
            competitionInfo={competitionInfo} 
            events={events} 
            onDataUpdate={refreshData} 
        />;
      case View.RACES:
        return <EventsView events={events} isLoading={isLoading} onSelectEvent={handleSelectEvent} onStartTiming={handleStartTiming} onDataUpdate={refreshData} />;
      case View.PARTICIPANTS:
          return <ParticipantsView swimmers={swimmers} events={events} onUploadSuccess={refreshData} competitionInfo={competitionInfo} />;
      case View.SWIMMERS_LIST:
          return <SwimmersView swimmers={swimmers} events={events} isLoading={isLoading} onDataUpdate={refreshData} initialState={navigationState} competitionInfo={competitionInfo} />;
      case View.RESULTS:
          return <ResultsView events={events} swimmers={swimmers} isLoading={isLoading} />;
      case View.PRINT_MENU:
          return <PrintView events={events} swimmers={swimmers} competitionInfo={competitionInfo} isLoading={isLoading} />;
      case View.USER_MANAGEMENT:
          if (currentUser.role === 'SUPER_ADMIN') {
              return <SqlEditorView />;
          }
          return <UserManagementView onDataUpdate={refreshData} />;
      default:
        return <AdminDashboard swimmers={swimmers} events={events} competitionInfo={competitionInfo} isLoading={isLoading} navigateTo={navigateTo}/>;
    }
  };

  if (currentView === View.LOGIN || currentView === View.PUBLIC_RESULTS || currentView === View.ONLINE_REGISTRATION || currentView === View.CHECKIN) {
      return (
        <>
          <NotificationContainer />
          {renderContent()}
        </>
      );
  }


  return (
    <div className="flex h-screen bg-background text-text-primary">
      <NotificationContainer />
      {/* Mobile Menu Overlay */}
      {isMenuOpen && (
        <div
          className="fixed inset-0 bg-black bg-opacity-50 z-30 md:hidden"
          onClick={() => setIsMenuOpen(false)}
          aria-hidden="true"
        ></div>
      )}
      <aside className={`w-64 bg-surface p-4 flex flex-col justify-between fixed inset-y-0 left-0 z-40 transform ${
        isMenuOpen ? 'translate-x-0' : '-translate-x-full'
      } transition-transform duration-300 ease-in-out md:relative md:translate-x-0 no-print`}>
        <div>
            <div className="flex items-center space-x-3 pb-4 mb-4 border-b border-border">
                <svg viewBox="0 0 100 100" className="h-12 w-12 flex-shrink-0" fill="none" xmlns="http://www.w3.org/2000/svg">
                    <defs>
                        <linearGradient id="waveGradient" x1="20" y1="70" x2="80" y2="40" gradientUnits="userSpaceOnUse">
                            <stop stopColor="#0077BE"/>
                            <stop offset="1" stopColor="#00A8E8"/>
                        </linearGradient>
                    </defs>
                    {/* Stopwatch shape */}
                    <circle cx="50" cy="54" r="38" stroke="#003F88" strokeWidth="6" fill="white"/>
                    <path d="M42 16 H58" stroke="#003F88" strokeWidth="6" strokeLinecap="round"/>
                    <path d="M50 16 V8" stroke="#003F88" strokeWidth="6" strokeLinecap="round"/>
                    <path d="M78 28 L84 22" stroke="#003F88" strokeWidth="6" strokeLinecap="round"/>

                    {/* Wave */}
                    <path d="M25 68 C 35 50, 55 52, 60 62 C 65 72, 75 70, 80 65 L 80 85 L 25 85 Z" fill="url(#waveGradient)"/>
                </svg>
                <div>
                    <h1 className="text-xl font-bold text-primary" style={{fontStyle: 'italic'}}>R.E.A.C.T</h1>
                    <p className="text-xs text-text-secondary leading-tight">Real-time Evaluation for Aquatic Competition & Timing</p>
                </div>
            </div>
            <nav className="space-y-2">
                <NavLink label="Dashboard" icon={<DashboardIcon />} isActive={currentView === View.ADMIN_DASHBOARD} onClick={() => navigateTo(View.ADMIN_DASHBOARD)}/>
                <NavLink label="Pengaturan Acara" icon={<CogIcon />} isActive={currentView === View.EVENT_SETTINGS} onClick={() => navigateTo(View.EVENT_SETTINGS)}/>
                <NavLink label="Nomor Lomba" icon={<ClipboardListIcon />} isActive={currentView === View.RACES || currentView === View.LIVE_TIMING} onClick={() => navigateTo(View.RACES)}/>
                <NavLink label="Unggah Peserta" icon={<UploadIcon />} isActive={currentView === View.PARTICIPANTS} onClick={() => navigateTo(View.PARTICIPANTS)}/>
                <NavLink label="Daftar Atlet" icon={<UsersIcon />} isActive={currentView === View.SWIMMERS_LIST} onClick={() => navigateTo(View.SWIMMERS_LIST)}/>
                <NavLink label="Hasil Lomba" icon={<MedalIcon />} isActive={currentView === View.RESULTS} onClick={() => navigateTo(View.RESULTS)}/>
                <NavLink label="Unduh Laporan" icon={<PrintIcon />} isActive={currentView === View.PRINT_MENU} onClick={() => navigateTo(View.PRINT_MENU)}/>
                {currentUser?.role === 'SUPER_ADMIN' && (
                    <NavLink label="SQL Editor" icon={<DatabaseIcon />} isActive={currentView === View.USER_MANAGEMENT} onClick={() => navigateTo(View.USER_MANAGEMENT)}/>
                )}
            </nav>
        </div>
        <div className="space-y-2">
            <ConnectionStatusIndicator internetStatus={internetStatus} dbStatus={dbStatus} arduinoStatus={arduinoStatus} />
            <ThemeToggle />
            <Button onClick={handleLogout} variant="secondary" className="w-full flex items-center justify-center space-x-2">
                <LogoutIcon />
                <span>Logout</span>
            </Button>
        </div>
      </aside>
      <main className="flex-1 flex flex-col overflow-y-auto">
        {/* Mobile Header */}
        <header className="md:hidden flex items-center p-4 border-b border-border bg-surface/80 backdrop-blur-sm sticky top-0 z-20 no-print">
            <button
                onClick={() => setIsMenuOpen(true)}
                className="p-2 rounded-md text-text-secondary hover:bg-background focus:outline-none focus:ring-2 focus:ring-inset focus:ring-primary"
                aria-label="Open menu"
            >
                <HamburgerIcon />
            </button>
            <h1 className="text-lg font-bold text-primary ml-4 truncate">
                {competitionInfo?.eventName.split('\n')[0] || "R.E.A.C.T"}
            </h1>
        </header>

        <div className="p-8 flex-grow">
          {renderContent()}
        </div>
      </main>
    </div>
  );
};

export default App;

import React, { useState, useMemo } from 'react';
import type { SwimEvent } from '../types';
import { SwimStyle, Gender } from '../types';
import { addEvent, deleteEvent, processEventUpload, deleteAllEvents } from '../services/databaseService';
import { SWIM_STYLE_OPTIONS, GENDER_OPTIONS, translateGender, translateSwimStyle, GENDER_TRANSLATIONS, SWIM_STYLE_TRANSLATIONS, formatEventName, romanize } from '../constants';
import { Button } from './ui/Button';
import { Modal } from './ui/Modal';
import { Input } from './ui/Input';
import { Select } from './ui/Select';
import { Card } from './ui/Card';
import { Spinner } from './ui/Spinner';
import { useNotification } from './ui/NotificationManager';

declare var XLSX: any;

interface EventsViewProps {
  events: SwimEvent[];
  isLoading: boolean;
  onSelectEvent: (id: string) => void;
  onStartTiming: (id: string) => void;
  onDataUpdate: () => void;
}

const TrashIcon = () => (
    <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
        <path strokeLinecap="round" strokeLinejoin="round" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" />
    </svg>
);

const StopwatchIcon = () => (
    <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z" />
    </svg>
);

const UsersIcon = () => (
    <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
        <path strokeLinecap="round" strokeLinejoin="round" d="M17 20h5v-2a3 3 0 00-5.356-1.857M17 20H7m10 0v-2c0-.653-.124-1.283-.356-1.857M7 20v-2c0-.653.124-1.283.356-1.857m0 0a5.002 5.002 0 019.288 0M15 7a3 3 0 11-6 0 3 3 0 016 0zm6 3a2 2 0 11-4 0 2 2 0 014 0zM7 10a2 2 0 11-4 0 2 2 0 014 0z" />
    </svg>
);

const CheckCircleIcon = () => (
    <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
        <path strokeLinecap="round" strokeLinejoin="round" d="M9 12l2 2 4-4m6 2a9 9 0 11-18 0 9 9 0 0118 0z" />
    </svg>
);

export const EventsView: React.FC<EventsViewProps> = ({ events, isLoading, onSelectEvent, onStartTiming, onDataUpdate }) => {
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [isDeleteModalOpen, setIsDeleteModalOpen] = useState(false);
  const [isDeleteAllModalOpen, setIsDeleteAllModalOpen] = useState(false);
  const [eventToDelete, setEventToDelete] = useState<SwimEvent | null>(null);
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedSession, setSelectedSession] = useState<number>(0); // 0 for all, -1 for unscheduled
  const [newEvent, setNewEvent] = useState({
    distance: 100,
    style: SwimStyle.FREESTYLE,
    gender: Gender.MALE,
    isRelay: false, // Initializer provided
    relayLegs: 4,
    category: '',
  });
  const [uploadResult, setUploadResult] = useState<{ success: number; errors: string[] } | null>(null);
  const { addNotification } = useNotification();

  // State for upload modal
  const [isUploadModalOpen, setIsUploadModalOpen] = useState(false);
  const [uploadFile, setUploadFile] = useState<File | null>(null);
  const [isProcessingUpload, setIsProcessingUpload] = useState(false);

  // Explicitly typed options for rendering to prevent type errors
  const genderOptions: Gender[] = GENDER_OPTIONS;
  const styleOptions: SwimStyle[] = SWIM_STYLE_OPTIONS;

  const hasSchemaError = useMemo(() => {
    if (!uploadResult || !uploadResult.errors) return false;
    return uploadResult.errors.some(err => 
        err.toLowerCase().includes('skema database anda mungkin perlu diperbarui') ||
        err.toLowerCase().includes('invalid input value for enum public.swim_style')
    );
  }, [uploadResult]);

  const sessions = useMemo(() => {
    if (!events) return { scheduled: [], unscheduledExists: false };
    const sessionNumbers = new Set(events.map(e => e.sessionNumber || 0));
    const scheduled = Array.from(sessionNumbers).filter((s: number) => s > 0).sort((a: number, b: number) => a - b);
    const unscheduledExists = sessionNumbers.has(0);
    return { scheduled, unscheduledExists };
  }, [events]);

  const groupedEvents = useMemo(() => {
    const grouped = events.reduce((acc: Record<number, SwimEvent[]>, event: SwimEvent) => {
        const sessionNum = event.sessionNumber || 0;
        if (!acc[sessionNum]) {
            acc[sessionNum] = [];
        }
        acc[sessionNum].push(event);
        return acc;
    }, {} as Record<number, SwimEvent[]>);

    // Sorting within sessions
    Object.values(grouped).forEach((sessionEvents: SwimEvent[]) => {
      sessionEvents.sort((a, b) => (a.heatOrder ?? 999) - (b.heatOrder ?? 999));
    });

    const filteredAndGrouped: Record<string, SwimEvent[]> = {};
    const sessionKeys = Object.keys(grouped).map(Number).sort((a: number, b: number) => a - b);

    sessionKeys.forEach((sessionNum: number) => {
        const sessionMatch = selectedSession === 0 ||
            (selectedSession === -1 && sessionNum === 0) ||
            (sessionNum === selectedSession);

        if (sessionMatch) {
            const eventsInSession = grouped[sessionNum].filter((event: SwimEvent) => 
                !searchQuery || formatEventName(event).toLowerCase().includes(searchQuery.toLowerCase())
            );

            if (eventsInSession.length > 0) {
                const sessionName = sessionNum === 0 ? 'Belum Terjadwal' : `Sesi ${romanize(sessionNum)}`;
                filteredAndGrouped[sessionName] = eventsInSession;
            }
        }
    });

    return filteredAndGrouped;
  }, [events, searchQuery, selectedSession]);

  const handleAddEvent = async (e: React.FormEvent) => {
    e.preventDefault();
    if (newEvent.distance <= 0) {
        addNotification("Jarak lomba harus lebih besar dari 0.", 'error');
        return;
    }

    try {
        await addEvent({
            distance: newEvent.distance,
            style: newEvent.style,
            gender: newEvent.gender,
            relayLegs: newEvent.isRelay ? newEvent.relayLegs : null,
            category: newEvent.category || null,
        });
        setNewEvent({
            distance: 100,
            style: SwimStyle.FREESTYLE,
            gender: Gender.MALE,
            isRelay: false,
            relayLegs: 4,
            category: '',
        });
        setIsModalOpen(false);
        onDataUpdate();
        addNotification('Nomor lomba baru berhasil dibuat.', 'success');
    } catch (error) {
        let errorMessage = "Terjadi kesalahan saat menyimpan.";
        if (error instanceof Error) {
            const lowerMessage = error.message.toLowerCase();
            if (lowerMessage.includes('invalid input value for enum public.swim_style') ||
                (lowerMessage.includes('violates check constraint') && lowerMessage.includes('events_style_check'))) {
                errorMessage = `Gagal menyimpan gaya "${translateSwimStyle(newEvent.style)}". Skema database Anda mungkin perlu diperbarui.`;
            } else {
                errorMessage = error.message;
            }
        }
        addNotification(errorMessage, 'error');
    }
  };

  const openDeleteConfirm = (event: SwimEvent) => {
    setEventToDelete(event);
    setIsDeleteModalOpen(true);
  };

  const closeDeleteConfirm = () => {
    setEventToDelete(null);
    setIsDeleteModalOpen(false);
  };

  const handleDeleteEvent = async () => {
    if (eventToDelete) {
        try {
            await deleteEvent(eventToDelete.id);
            addNotification('Nomor lomba berhasil dihapus.', 'error');
            closeDeleteConfirm();
            onDataUpdate();
        } catch (error: any) {
            addNotification(`Gagal menghapus: ${error.message}`, 'error');
        }
    }
  };

  const handleConfirmDeleteAll = async () => {
    try {
        await deleteAllEvents();
        addNotification('Semua nomor lomba berhasil dihapus.', 'error');
        setIsDeleteAllModalOpen(false);
        onDataUpdate();
    } catch (error: any) {
        addNotification(`Gagal menghapus: ${error.message}`, 'error');
    }
  };

  const closeUploadModal = () => {
    setIsUploadModalOpen(false);
    setUploadFile(null);
    setUploadResult(null);
    setIsProcessingUpload(false);
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      setUploadFile(e.target.files[0]);
      setUploadResult(null);
    }
  };

  const handleProcessUpload = () => {
    if (!uploadFile) return;

    setIsProcessingUpload(true);
    setUploadResult(null);

    const reader = new FileReader();
    reader.onload = async (e) => {
        try {
            const data = new Uint8Array(e.target?.result as ArrayBuffer);
            const workbook = XLSX.read(data, { type: 'array' });
            const sheetName = workbook.SheetNames[0];
            const worksheet = workbook.Sheets[sheetName];
            const json: any[] = XLSX.utils.sheet_to_json(worksheet);

            const result = await processEventUpload(json);
            setUploadResult(result);

            if (result.errors.length === 0 && result.success > 0) {
                addNotification(`${result.success} nomor lomba berhasil diimpor.`, 'success');
                onDataUpdate();
                setTimeout(() => {
                    closeUploadModal();
                }, 2000);
            } else if (result.errors.length > 0) {
                addNotification(`Impor selesai with ${result.errors.length} galat. Periksa detail di bawah.`, 'error');
            }
        } catch (error: any) {
            addNotification(`Gagal memproses file: ${error.message}`, 'error');
            setUploadResult({ success: 0, errors: ['Gagal membaca atau memproses file.', error.message] });
        } finally {
            setIsProcessingUpload(false);
        }
    };
    reader.readAsArrayBuffer(uploadFile);
  };

  const handleDownloadTemplate = () => {
    if (typeof XLSX === 'undefined') {
        alert('Pustaka untuk membuat file Excel belum termuat. Periksa koneksi internet Anda dan muat ulang halaman.');
        return;
    }
    const wb = XLSX.utils.book_new();

    // --- Sheet 2: Petunjuk & Daftar Pilihan ---
    const listsSheetData: any[][] = [
        ["PETUNJUK PENGISIAN"],
        ["1. Isi data nomor lomba pada sheet 'Template Nomor Lomba'."],
        ["2. Kolom 'Jarak (m)', 'Gaya', and 'Jenis Kelamin' wajib diisi."],
        ["3. Untuk Gaya and Jenis Kelamin, mohon gunakan pilihan yang tersedia di dropdown."],
        ["4. Kolom 'Kategori' bersifat opsional. Kosongkan jika tidak ada (cth: untuk event senior/open)."],
        ["5. Kolom 'Jumlah Atlet' HANYA diisi untuk nomor estafet (relay), contoh: 4. Kosongkan untuk perorangan."],
        [], // Spacer
        ["DAFTAR PILIHAN VALID"],
        [],
        ["Gaya", "Jenis Kelamin"],
    ];

    const styles: string[] = Object.values(SWIM_STYLE_TRANSLATIONS);
    const genders: string[] = Object.values(GENDER_TRANSLATIONS);
    const maxLength = Math.max(styles.length, genders.length);

    for (let i = 0; i < maxLength; i++) {
        listsSheetData.push([ styles[i] || "", genders[i] || "" ]);
    }
    const ws_lists = XLSX.utils.aoa_to_sheet(listsSheetData);
    ws_lists['!cols'] = [{ wch: 40 }, { wch: 20 }];
    XLSX.utils.book_append_sheet(wb, ws_lists, "Petunjuk & Pilihan");


    // --- Sheet 1: Template Nomor Lomba ---
    const templateData = [
        {
            "Jarak (m)": 50,
            "Gaya": "Gaya Kupu-kupu",
            "Jenis Kelamin": "Putri",
            "Kategori": "KU 1-2",
            "Jumlah Atlet": "" // Individual event
        },
        {
            "Jarak (m)": 200,
            "Gaya": "Gaya Bebas",
            "Jenis Kelamin": "Putra",
            "Kategori": "", // Open/Senior event
            "Jumlah Atlet": ""
        },
        {
            "Jarak (m)": 100, // Distance per leg
            "Gaya": "Gaya Ganti Perorangan",
            "Jenis Kelamin": "Campuran",
            "Kategori": "KU-3",
            "Jumlah Atlet": 4 // Relay event
        },
        {
            "Jarak (m)": 25,
            "Gaya": "Papan Luncur / Kickboard",
            "Jenis Kelamin": "Putra",
            "Kategori": "KU-4",
            "Jumlah Atlet": ""
        }
    ];

    const ws = XLSX.utils.json_to_sheet(templateData);
    ws['!cols'] = [ { wch: 10 }, { wch: 25 }, { wch: 15 }, { wch: 15 }, { wch: 20 }];

    // Add Data Validation to Sheet 1
    const maxRows = 1000;
    if (!ws['!dataValidation']) ws['!dataValidation'] = [];
    ws['!dataValidation'].push({ sqref: `B2:B${maxRows}`, opts: { type: 'list', formula1: `'Petunjuk & Pilihan'!$A$11:$A$${10 + styles.length}` } });
    ws['!dataValidation'].push({ sqref: `C2:C${maxRows}`, opts: { type: 'list', formula1: `'Petunjuk & Pilihan'!$B$11:$B$${10 + genders.length}` } });

    XLSX.utils.book_append_sheet(wb, ws, "Template Nomor Lomba");

    // Reorder sheets to have Template first
    wb.SheetNames.reverse();

    XLSX.writeFile(wb, "Template_Nomor_Lomba.xlsx");
  };

  const handleDownloadEvents = () => {
    if (typeof XLSX === 'undefined') {
        alert('Pustaka untuk membuat file Excel belum termuat. Periksa koneksi internet Anda and muat ulang halaman.');
        return;
    }
    if (events.length === 0) {
        alert('Tidak ada nomor lomba untuk diunduh.');
        return;
    }

    const sortedEvents: SwimEvent[] = [...events].sort((a, b) => {
         const sessionNumberA = a.sessionNumber ?? 999;
         const sessionNumberB = b.sessionNumber ?? 999;
         const sessionDiff = sessionNumberA - sessionNumberB;
         if (sessionDiff !== 0) return sessionDiff;
         const heatOrderA = a.heatOrder ?? 999;
         const heatOrderB = b.heatOrder ?? 999;
         const orderDiff = heatOrderA - heatOrderB;
         if (orderDiff !== 0) return orderDiff;
         return formatEventName(a).localeCompare(formatEventName(b));
    });

    const dataToExport = sortedEvents.map(event => ({
        "Jarak (m)": event.distance,
        "Gaya": translateSwimStyle(event.style),
        "Jenis Kelamin": translateGender(event.gender),
        "Kategori": event.category || "",
        "Jumlah Atlet": event.relayLegs || ""
    }));

    const worksheet = XLSX.utils.json_to_sheet(dataToExport);
    worksheet['!cols'] = [
        { wch: 10 }, // Jarak
        { wch: 25 }, // Gaya
        { wch: 15 }, // Jenis Kelamin
        { wch: 15 }, // Kategori
        { wch: 20 }  // Jumlah Atlet
    ];

    const workbook = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(workbook, worksheet, "Daftar Nomor Lomba");
    XLSX.writeFile(workbook, "Daftar_Nomor_Lomba_Saat_Ini.xlsx");
  };


  return (
    <div>
      <div className="flex justify-between items-center mb-6 flex-wrap gap-2">
        <h1 className="text-3xl font-bold">Nomor Lomba</h1>
        <div className="flex space-x-2 flex-wrap gap-2">
            <Button onClick={handleDownloadEvents} variant="secondary" disabled={events.length === 0} title="Unduh semua nomor lomba yang ada">Unduh Nomor Lomba</Button>
            <Button onClick={() => setIsUploadModalOpen(true)} variant="secondary">Unggah Nomor Lomba</Button>
            <Button onClick={() => setIsModalOpen(true)}>Buat Nomor Lomba</Button>
            <Button 
                variant="danger" 
                onClick={() => setIsDeleteAllModalOpen(true)}
                disabled={events.length === 0}
                title={events.length === 0 ? "Tidak ada nomor lomba untuk dihapus" : "Hapus semua nomor lomba"}
            >
                Hapus Semua Nomor Lomba
            </Button>
        </div>
      </div>

      <Card className="mb-6">
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            <div>
                <p className="text-sm font-medium text-text-secondary mb-2">Filter berdasarkan Sesi</p>
                <div className="flex flex-wrap gap-2">
                    <Button variant={selectedSession === 0 ? 'primary' : 'secondary'} onClick={() => setSelectedSession(0)}>Semua</Button>
                    {sessions.scheduled.map((num: number) => (
                        <Button key={num} variant={selectedSession === num ? 'primary' : 'secondary'} onClick={() => setSelectedSession(num)}>Sesi {romanize(num)}</Button>
                    ))}
                    {sessions.unscheduledExists && (
                        <Button variant={selectedSession === -1 ? 'primary' : 'secondary'} onClick={() => setSelectedSession(-1)}>Belum Terjadwal</Button>
                    )}
                </div>
            </div>
            <div>
                <Input
                label="Cari Nomor Lomba"
                id="event-search"
                type="text"
                placeholder="Cth: 50m Gaya Bebas KU 1-2 Putra..."
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
                />
            </div>
        </div>
      </Card>

      <Card>
        {isLoading ? (
            <div className="flex justify-center items-center py-10">
                <Spinner />
                <p className="ml-2 text-text-secondary">Memuat nomor lomba...</p>
            </div>
        ) : Object.keys(groupedEvents).length > 0 ? (
            <div className="space-y-6">
                {Object.entries(groupedEvents).map(([sessionName, eventsInSession]) => (
                    <div key={sessionName}>
                        <h2 className="text-xl font-bold text-primary border-b-2 border-primary/20 pb-2 mb-3">{sessionName}</h2>
                        <div className="space-y-2">
                            {eventsInSession.map((event: SwimEvent) => {
                                const recordedCount = event.results.length;
                                const entryCount = event.entries.length;
                                const hasEntries = entryCount > 0;
                                const needsTiming = hasEntries && recordedCount < entryCount;

                                let statusText: string;
                                let statusColor: string;

                                if (!hasEntries) {
                                    statusText = 'Belum Ada Hasil';
                                    statusColor = '';
