                                    statusColor = 'text-green-500';
                                } else { // recordedCount < entryCount
                                    const missingCount = entryCount - recordedCount;
                                    statusText = `${recordedCount} Hasil Tercatat (${missingCount} belum ada hasil)`;
                                    statusColor = 'text-yellow-500';
                                }

