        swimmerCategory: 'KLASEMEN PERORANGAN (PER KATEGORI)',
        brokenRecords: 'DAFTAR REKOR TERPECAHKAN',
        onlineRegistration: 'LAPORAN PENDAFTARAN ONLINE & PEMBAYARAN',
