                <ReportHeader info={competitionInfo} title={reportTitles[reportType]} />

                {reportType === 'schedule' && <ScheduleReport events={baseEvents} />}

                {reportType === 'program' && (
                    <EventBaseReport 
                        events={processedData.detailedEvents} 
                        info={competitionInfo} 
                        records={records} 
                    />
                )}

                {reportType === 'results' && (
                    <EventBaseReport 
                        events={processedData.detailedEvents} 
                        info={competitionInfo} 
